public class Main {

    static double calculate(double a, double b, String op) {
        switch (op) {
            case "+": return a + b;
            case "-": return a - b;
            case "*": return a * b;
            case "/":
                if (b == 0) {
                    System.out.println("Hata: Sifira bolme!");
                    return Double.NaN;
                }
                return a / b;
            default:
                System.out.println("Gecersiz islem: " + op);
                return Double.NaN;
        }
    }

    public static void main(String[] args) {
        double x = 15, y = 4;

        System.out.println("x = " + x + ", y = " + y);
        System.out.println("x + y = " + calculate(x, y, "+"));
        System.out.println("x - y = " + calculate(x, y, "-"));
        System.out.println("x * y = " + calculate(x, y, "*"));
        System.out.println("x / y = " + calculate(x, y, "/"));

        System.out.println("\nSifira bolme testi:");
        calculate(10, 0, "/");

        // Yuzde hesaplama
        double total = 250, discount = 15;
        double finalPrice = total - (total * discount / 100);
        System.out.println("\n" + total + " TL'nin %" + discount + " indirimli hali: " + finalPrice + " TL");
    }
}
